'use client';

import { useState, useEffect, useCallback } from 'react';
import { OrderUpdate } from '@/components/orders/OrderNotificationSystem';

interface UseOrderNotificationsReturn {
  notifications: OrderUpdate[];
  addNotification: (update: Omit<OrderUpdate, 'id' | 'timestamp'>) => void;
  removeNotification: (id: string) => void;
  markAsViewed: (id: string) => void;
  clearAll: () => void;
}

export const useOrderNotifications = (): UseOrderNotificationsReturn => {
  const [notifications, setNotifications] = useState<OrderUpdate[]>([]);

  // Simulate receiving order updates (in real app, this would come from websocket/API)
  useEffect(() => {
    // Simulate an order update after 5 seconds (for demo)
    const timer = setTimeout(() => {
      addNotification({
        orderId: 'ORDER123456789',
        status: 'packed',
        message: 'Your order has been packed and is ready for shipping',
        estimatedDelivery: 'Tomorrow, 2-4 PM'
      });
    }, 5000);

    // Simulate another update after 10 seconds
    const timer2 = setTimeout(() => {
      addNotification({
        orderId: 'ORDER123456789',
        status: 'shipped',
        message: 'Your order is out for delivery',
        estimatedDelivery: 'Today, 2-4 PM'
      });
    }, 10000);

    return () => {
      clearTimeout(timer);
      clearTimeout(timer2);
    };
  }, []);

  const addNotification = useCallback((update: Omit<OrderUpdate, 'id' | 'timestamp'>) => {
    const newNotification: OrderUpdate = {
      ...update,
      id: `notification-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: new Date()
    };

    setNotifications(prev => [newNotification, ...prev.slice(0, 2)]); // Keep max 3 notifications
  }, []);

  const removeNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(notification => notification.id !== id));
  }, []);

  const markAsViewed = useCallback((id: string) => {
    // In a real app, you might want to mark this in backend/local storage
    console.log('Notification viewed:', id);
  }, []);

  const clearAll = useCallback(() => {
    setNotifications([]);
  }, []);

  return {
    notifications,
    addNotification,
    removeNotification,
    markAsViewed,
    clearAll
  };
};
