'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Package, Truck, CheckCircle, Clock, X } from 'lucide-react';
import { useRouter } from 'next/navigation';

interface OrderUpdate {
  id: string;
  orderId: string;
  status: 'processing' | 'packed' | 'shipped' | 'delivered';
  message: string;
  timestamp: Date;
  estimatedDelivery?: string;
}

interface OrderNotificationProps {
  update: OrderUpdate;
  onClose: () => void;
  onView: () => void;
}

const OrderNotification = ({ update, onClose, onView }: OrderNotificationProps) => {
  const [progress, setProgress] = useState(100);
  const router = useRouter();

  useEffect(() => {
    // Auto-close timer with progress bar (8 seconds)
    const timer = setTimeout(() => {
      onClose();
    }, 8000);
    
    // Update progress bar
    const interval = setInterval(() => {
      setProgress(prev => Math.max(prev - 1.25, 0)); // 100/80 = 1.25 per 100ms
    }, 100);
    
    return () => {
      clearTimeout(timer);
      clearInterval(interval);
    };
  }, [onClose]);

  const getStatusIcon = () => {
    switch (update.status) {
      case 'processing':
        return <Clock className="h-5 w-5 text-orange-500" />;
      case 'packed':
        return <Package className="h-5 w-5 text-blue-500" />;
      case 'shipped':
        return <Truck className="h-5 w-5 text-purple-500" />;
      case 'delivered':
        return <CheckCircle className="h-5 w-5 text-green-500" />;
      default:
        return <Package className="h-5 w-5 text-gray-500" />;
    }
  };

  const getStatusColor = () => {
    switch (update.status) {
      case 'processing':
        return 'border-orange-200 bg-orange-50';
      case 'packed':
        return 'border-blue-200 bg-blue-50';
      case 'shipped':
        return 'border-purple-200 bg-purple-50';
      case 'delivered':
        return 'border-green-200 bg-green-50';
      default:
        return 'border-gray-200 bg-gray-50';
    }
  };

  const handleClick = () => {
    onView();
    router.push(`/track-order?orderId=${update.orderId}`);
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: 300, scale: 0.8 }}
      animate={{ opacity: 1, x: 0, scale: 1 }}
      exit={{ opacity: 0, x: 300, scale: 0.8 }}
      transition={{ duration: 0.4, ease: "easeOut" }}
      className={`fixed top-20 right-4 z-50 w-80 max-w-[calc(100vw-2rem)] ${getStatusColor()} border rounded-xl shadow-lg overflow-hidden cursor-pointer`}
      onClick={handleClick}
    >
      <div className="p-4">
        <div className="flex items-start justify-between">
          <div className="flex items-center space-x-3">
            <div className="flex-shrink-0">
              {getStatusIcon()}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-gray-900">
                Order #{update.orderId.slice(-6).toUpperCase()}
              </p>
              <p className="text-sm text-gray-600 mt-1">
                {update.message}
              </p>
              {update.estimatedDelivery && (
                <p className="text-xs text-gray-500 mt-1">
                  Est. delivery: {update.estimatedDelivery}
                </p>
              )}
            </div>
          </div>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onClose();
            }}
            className="flex-shrink-0 text-gray-400 hover:text-gray-500 focus:outline-none ml-2"
          >
            <X className="h-4 w-4" />
          </button>
        </div>
        
        <div className="mt-3">
          <div className="text-xs text-gray-500 mb-1">Click to track your order</div>
          <div className="text-xs text-gray-400">
            {new Date(update.timestamp).toLocaleTimeString()}
          </div>
        </div>
      </div>
      
      {/* Progress bar */}
      <div className="h-1 w-full bg-gray-200">
        <motion.div 
          className="h-full bg-tendercuts-red"
          initial={{ width: '100%' }}
          animate={{ width: `${progress}%` }}
          transition={{ duration: 0.1, ease: 'linear' }}
        />
      </div>
    </motion.div>
  );
};

interface OrderNotificationSystemProps {
  updates: OrderUpdate[];
  onUpdateViewed: (updateId: string) => void;
  onUpdateRemoved: (updateId: string) => void;
}

const OrderNotificationSystem = ({ 
  updates, 
  onUpdateViewed, 
  onUpdateRemoved 
}: OrderNotificationSystemProps) => {
  return (
    <div className="fixed top-0 right-0 z-50 p-4 pointer-events-none">
      <AnimatePresence mode="sync">
        {updates.map((update, index) => (
          <motion.div
            key={update.id}
            initial={{ y: -100 }}
            animate={{ y: index * 120 }}
            exit={{ y: -100 }}
            transition={{ duration: 0.3 }}
            className="pointer-events-auto mb-4"
          >
            <OrderNotification
              update={update}
              onClose={() => onUpdateRemoved(update.id)}
              onView={() => onUpdateViewed(update.id)}
            />
          </motion.div>
        ))}
      </AnimatePresence>
    </div>
  );
};

export default OrderNotificationSystem;
export type { OrderUpdate };
